import base64
import os
import xml.etree.ElementTree as ET
from flask import Flask, request, session, redirect, url_for, render_template_string

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, permanent secret key for production

# --- Configuration ---
# This is where your IdP would send the SAMLResponse
SP_ACS_URL = "http://localhost:5000/sso/acs"

# A dummy IdP SSO URL for demonstration (you would get this from your IdP)
# In a real scenario, you'd typically initiate a redirect to this URL
# with an AuthnRequest, but for this example, we assume an IdP-initiated flow
# or simulate an IdP POSTing directly to ACS.
DUMMY_IDP_SSO_URL = "http://your.idp.com/sso/saml"

# XML Namespaces for easier parsing
NAMESPACES = {
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'ds': 'http://www.w3.org/2000/09/xmldsig#',
    'xenc': 'http://www.w3.org/2001/04/xmlenc#',
}

# --- Helper Function for XML parsing ---
def extract_saml_attributes(saml_response_xml):
    root = ET.fromstring(saml_response_xml)

    assertions = root.findall('saml:Assertion', NAMESPACES)

    if not assertions:
        raise ValueError("SAML Response does not contain any Assertions.")

    # In a real scenario, you might iterate through assertions or
    # apply more complex logic to choose the correct one.
    # For simplicity, we take the first assertion.
    assertion = assertions[0]

    user_attributes = {}

    # Extract Subject NameID (e.g., username, email)
    name_id = assertion.find('saml:Subject/saml:NameID', NAMESPACES)
    if name_id is not None:
        user_attributes['NameID'] = name_id.text

    # Extract attributes from AttributeStatement
    attribute_statement = assertion.find('saml:AttributeStatement', NAMESPACES)
    if attribute_statement is not None:
        for attribute in attribute_statement.findall('saml:Attribute', NAMESPACES):
            name = attribute.get('Name')
            if name:
                # SAML attributes can have multiple values, we take the first one
                attribute_value = attribute.find('saml:AttributeValue', NAMESPACES)
                if attribute_value is not None:
                    user_attributes[name] = attribute_value.text

    return user_attributes

